#endif

    size_t start_idx = global_id * elements_per_thread * fusion_degree;

    class_T sum = 0;
    class_T f = data[0];

    // Process elements
    for (size_t elem = 0; elem < elements_per_thread; elem++) {
        size_t idx = start_idx + elem * fusion_degree;

        // Fusion loop
        for (size_t fusion = 0; fusion < fusion_degree; fusion++) {
